/** Lookup lore by PNG filename (without extension and path). */
export function getLore(iconPath: string): string | undefined {
  const filename = iconPath.split('/').pop()?.replace(/\.png$/, '') ?? '';
  return EQUIPMENT_LORE[filename];
}
